const data = $input.first().json;
const services = data.services || {};
const channels = data.channels || {};
const stats = data.factor_stats || {};
const events = data.recent_events || [];

const alerts = [];
const warnings = [];
const info = [];

// 服务状态
const downServices = Object.entries(services).filter(([k, v]) => !v.running).map(([k]) => k);
if (downServices.length > 0) {
  alerts.push(`❌ 服务宕机: ${downServices.join(', ')}`);
}
const upServices = Object.entries(services).filter(([k, v]) => v.running).map(([k]) => k);
info.push(`🟢 运行中: ${upServices.join(', ')}`);

// Redis
if (!data.redis) {
  alerts.push('❌ Redis 连接失败');
}

// 渠道心跳
const offlineChannels = Object.entries(channels).filter(([k, v]) => !v.online).map(([k]) => k);
if (offlineChannels.length > 0) {
  warnings.push(`⚠️ 渠道离线: ${offlineChannels.join(', ')}`);
}

// SOUL 完整性
if (!data.soul_ok) {
  alerts.push('❌ SOUL 数据缺失或损坏');
}

// 因子库
const count = stats.active_count || 0;
if (count < 20) {
  warnings.push(`⚠️ 因子库偏少: ${count} (目标 > 50)`);
} else {
  info.push(`📦 因子库: ${count} 个活跃因子`);
}

// 质量
if (stats.avg_sharpe && stats.avg_sharpe < 0.8) {
  warnings.push(`⚠️ 平均 Sharpe 偏低: ${stats.avg_sharpe.toFixed(3)}`);
} else {
  info.push(`📊 平均 Sharpe: ${(stats.avg_sharpe || 0).toFixed(3)}`);
}
info.push(`🏆 最佳 Sharpe: ${(stats.best_sharpe || 0).toFixed(3)}`);

// 记忆实体
info.push(`🧠 记忆实体: ${data.memory_entities || 0}`);

// ReflectionEngine 洞察
const insight = data.reflection_insight;
if (insight && insight !== '📊 今日暂无查询数据') {
  info.push(`\n${insight}`);
}

// 失败率高的 Agent
const failingAgents = data.failing_agents || [];
if (failingAgents.length > 0) {
  warnings.push(`⚠️ Agent 失败率过高: ${failingAgents.join(', ')}`);
}

// selfimprove 建议
const needsSelfimprove = data.needs_selfimprove;
const reasons = data.selfimprove_reasons || [];
if (reasons.length > 0) {
  warnings.push(`\n🔧 selfimprove 建议:\n  ${reasons.join('\n  ')}`);
}

const hasAlerts = alerts.length > 0;
const hasWarnings = warnings.length > 0;

let emoji = '🟢';
if (hasAlerts) emoji = '🔴';
else if (hasWarnings) emoji = '🟡';

let msg = `${emoji} rragents 系统状态 ${new Date().toLocaleString()}\n`;
msg += `━━━━━━━━━━━━━━━━━━\n`;
if (alerts.length) msg += alerts.join('\n') + '\n\n';
if (warnings.length) msg += warnings.join('\n') + '\n\n';
msg += info.join('\n');

return [{json: {
  hasAlerts, hasWarnings, needsSelfimprove,
  alertCount: alerts.length, warningCount: warnings.length,
  message: msg
}}];
